package sandbox

import "testing"

func TestIsEven(t *testing.T) {
	cases := []struct {
		name string
		in   int
		want bool
	}{
		{"zero", 0, true},
		{"even", 4, true},
		{"odd", 3, false},
		{"negative even", -2, true},
	}
	for _, c := range cases {
		t.Run(c.name, func(t *testing.T) {
			if got := IsEven(c.in); got != c.want {
				t.Fatalf("IsEven(%d) = %v, want %v", c.in, got, c.want)
			}
		})
	}
}
